        if start_time <= predicted_arrival <= end_time:
            time_penalty = 0
        elif predicted_arrival < start_time:
            time_penalty = historical_influence(start_time - predicted_arrival)
        else:
            time_penalty = float('inf')

        clustering_bonus = 0
        for other_idx, other_customer_pos in enumerate(unvisited_customers):
