                clustering_bonus += historical_influence(1)

        score = historical_influence(distance) + time_penalty - clustering_bonus
        if time_penalty < float('inf'):
            heapq.heappush(priority_queue, (score, idx))

    if priority_queue:
        _, best_node = heapq.heappop(priority_queue)
