def select_next_node(cur_truck_pos, depot_pos, all_truck_pos, unvisited_customers, current_time, truck_speed, time_windows):
    priority_queue = []

    def decay_function(value, base=0.95):
        return value * base ** len(unvisited_customers)

    for idx, (customer_pos, (start_time, end_time)) in enumerate(zip(unvisited_customers, time_windows)):
        distance = np.linalg.norm(customer_pos - cur_truck_pos)
        travel_time = decay_function(distance / truck_speed)
        arrival_time = current_time + travel_time

        if start_time <= arrival_time <= end_time:
            time_score = 0
        elif arrival_time < start_time:
            time_score = decay_function(start_time - arrival_time)
        else:
            time_score = float('inf')

        cluster_score = 0
        for other_idx, other_customer_pos in enumerate(unvisited_customers):
            if idx != other_idx and np.linalg.norm(customer_pos - other_customer_pos) < 20:
                cluster_score += decay_function(1)

        score = decay_function(distance) + time_score - cluster_score
        if time_score < float('inf'):
            heapq.heappush(priority_queue, (score, idx))

    if priority_queue:
        _, best_node = heapq.heappop(priority_queue)
    else:
        best_node = None

    return best_node
